function(context) {
  console.log("1. Initializing component...");
  console.log("1a. Context received:", context);

  var container = document.createElement('div');
  container.className = 'my-custom-component';
  // Ensure the container has height and a border so we can confirm it mounted
  container.style.cssText = "display: block !important; min-height: 50px !important; width: 100% !important; border: 2px solid #635dff !important; padding: 5px !important; visibility: visible !important; opacity: 1 !important; position: relative !important; background-color: white !important; z-index: 1 !important;";

  var fieldId = context.custom.getFieldId();
  console.log("1b. Field ID:", fieldId);

  var sel = document.createElement('select');
  sel.name = fieldId; // Set the name to the field ID
  sel.id = fieldId; // Set the id to the field ID
  sel.style.cssText = "width: 100% !important; height: 44px !important; padding: 10px !important; border: 1px solid #ccc !important; background: #fff !important; color: #000 !important; display: block !important; visibility: visible !important; opacity: 1 !important; font-size: 16px !important; position: relative !important; z-index: 2 !important;";
  sel.innerHTML = '<option value="">Loading products...</option>';
  container.appendChild(sel);

  console.log("1c. Select created with name/id:", fieldId);

  fetch('https://n5je6mqzsskozc32cqdfetl42q0augte.lambda-url.us-east-1.on.aws/api/ucp/products')
    .then(function(res) {
      console.log("2. Response:", res.status);
      return res.json();
    })
    .then(function(data) {
      console.log("3. Full API Response:", JSON.stringify(data, null, 2));
      console.log("3a. Products count:", data.count);
      console.log("3b. Products array:", data.products);
      console.log("3c. Is array?", Array.isArray(data.products));

      sel.innerHTML = '<option value="">-- Select a Product --</option>';

      if (data.success && data.products && Array.isArray(data.products)) {
        console.log("3d. About to render", data.products.length, "products");
        data.products.forEach(function(p, index) {
          console.log("3e. Rendering product", index, ":", p.title, p.price);
          var o = document.createElement('option');
          o.value = p.id;
          o.textContent = p.title + " ($" + p.price.value + ")";
          sel.appendChild(o);
        });
        console.log("4. Rendering complete. Select now has", sel.options.length, "options");
      } else {
        console.error("3d. Failed validation - success:", data.success, "has products:", !!data.products, "is array:", Array.isArray(data.products));
      }
    })
    .catch(function(err) {
      console.error("Fetch failed:", err);
      sel.innerHTML = '<option>Error loading products</option>';
    });

  sel.addEventListener('change', function(e) {
    var selectedValue = e.target.value;
    console.log("12. Product selected:", selectedValue);
    console.log("13. Select element value:", sel.value);
    console.log("14. Select element name:", sel.name);

    // Verify form values (it's a Promise)
    setTimeout(function() {
      context.form.getValues().then(function(formValues) {
        console.log("15. All form values:", formValues);
        console.log("16. custom_oECQ in formValues:", formValues && formValues[fieldId]);
      });
    }, 100); // Small delay to let Auth0 process the change
  });

  // Debug: Check if container gets mounted to the DOM
  setTimeout(function() {
    console.log("5. Container in DOM?", document.body.contains(container));
    console.log("6. Container styles:", window.getComputedStyle(container).display, window.getComputedStyle(container).visibility);
    console.log("7. Container parent:", container.parentElement);
    if (container.parentElement) {
      console.log("8. Parent styles:", window.getComputedStyle(container.parentElement).display, window.getComputedStyle(container.parentElement).visibility);
    } else {
      // Try to manually mount if Auth0 didn't do it
      console.log("9. Attempting manual mount...");
      var afCustom = document.querySelector('.af-custom');
      if (afCustom) {
        console.log("10. Found .af-custom element, mounting manually");
        afCustom.appendChild(container);
      } else {
        console.error("11. Could not find .af-custom element");
      }
    }

    // Test getValue after mount
    console.log("17. Testing context.custom.getValue():", context.custom.getValue());
  }, 1000);

  // Also check for Auth0 Forms errors
  console.log("Component function executed, returning container");

  return {
    element: container,
    getValue: function() {
      console.log("getValue() called, returning:", sel.value);
      return sel.value;
    }
  };
}
